head.b:skin:
/* ===== DARK MODERN PORTFOLIO THEME ===== */
:root {
  --primary: #6C63FF;
  --primary-dark: #5A52D5;
  --secondary: #36D1DC;
  --accent: #FF6584;
  --dark: #0F172A;
  --darker: #020617;
  --light: #F1F5F9;
  --gray: #64748B;
  --gray-light: #E2E8F0;
  --white: #FFFFFF;
  --text-light: #F8FAFC;
  --text-dark: #0F172A;
  --text-muted: #94A3B8;
  --glass: rgba(30, 41, 59, 0.7);
  --glass-border: rgba(255, 255, 255, 0.1);

  --shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
  --shadow-hover: 0 8px 30px rgba(0, 0, 0, 0.2);
  --shadow-glow: 0 0 20px rgba(108, 99, 255, 0.3);
  --transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  --radius: 12px;

  --gradient-primary: linear-gradient(135deg, #6C63FF 0%, #5A52D5 100%);
  --gradient-secondary: linear-gradient(135deg, #36D1DC 0%, #6C63FF 100%);
  --gradient-accent: linear-gradient(135deg, #FF6584 0%, #FF8E53 100%);
  --gradient-dark: linear-gradient(135deg, #0F172A 0%, #1E293B 100%);
  --gradient-glass: linear-gradient(145deg, rgba(30, 41, 59, 0.8), rgba(15, 23, 42, 0.9));
}

/* ===== RESET & BASE ===== */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  line-height: 1.7;
  color: var(--text-light);
  background-color: var(--darker);
  overflow-x: hidden;
  position: relative;
}

body::before {
  content: '';
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: radial-gradient(circle at 20% 30%, rgba(108, 99, 255, 0.03) 0%, transparent 30%),
              radial-gradient(circle at 80% 70%, rgba(54, 209, 220, 0.03) 0%, transparent 30%);
  pointer-events: none;
  z-index: -1;
}

body.modal-open {
  overflow: hidden;
}

.container {
  width: 100%;
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
}

/* ===== SECTION STYLES ===== */
section {
  width: 100%;
  position: relative;
  padding: 60px 0 !important;
  margin: 0 !important;
  overflow: hidden;
}

section::before {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(circle, rgba(108, 99, 255, 0.02) 0%, transparent 60%);
  opacity: 0.5;
  pointer-events: none;
}

.section-header {
  text-align: center;
  margin-bottom: 40px;
}

.section-header h2 {
  font-size: 2.5rem;
  margin-bottom: 15px;
  position: relative;
  display: inline-block;
  background: var(--gradient-primary);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  text-transform: capitalize;
}

.section-header h2::after {
  content: '';
  position: absolute;
  bottom: -8px;
  left: 50%;
  transform: translateX(-50%);
  width: 80px;
  height: 4px;
  background: var(--gradient-secondary);
  border-radius: 2px;
  transition: width 0.3s ease;
}

.section-header:hover h2::after {
  width: 120px;
}

.section-subtitle {
  color: var(--text-muted);
  max-width: 600px;
  margin: 15px auto 0;
  font-size: 1.1rem;
  line-height: 1.6;
}

/* ===== TYPOGRAPHY ===== */
h1, h2, h3, h4, h5, h6 {
  font-weight: 700;
  line-height: 1.2;
  margin-bottom: 0.8rem;
  color: var(--text-light);
}

h1 {
  font-size: 3.2rem;
  letter-spacing: -0.5px;
}

h2 {
  font-size: 2.5rem;
  letter-spacing: -0.3px;
}

h3 {
  font-size: 1.8rem;
}

p {
  margin-bottom: 1.2rem;
  color: var(--text-muted);
  font-size: 1rem;
}

a {
  color: var(--primary);
  text-decoration: none;
  transition: var(--transition);
}

a:hover {
  color: var(--secondary);
}

/* ===== BUTTONS ===== */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 14px 32px;
  border-radius: var(--radius);
  font-weight: 600;
  font-size: 0.95rem;
  text-decoration: none;
  transition: var(--transition);
  cursor: pointer;
  border: none;
  position: relative;
  overflow: hidden;
  z-index: 1;
  gap: 8px;
  letter-spacing: 0.5px;
}

.btn::before {
  content: '';
  position: absolute;
  top: 0;
  left: -100%;
  width: 100%;
  height: 100%;
  background: linear-gradient(90deg, transparent, rgba(255,255,255,0.2), transparent);
  transition: left 0.6s;
  z-index: -1;
}

.btn:hover::before {
  left: 100%;
}

.btn-primary {
  background: var(--gradient-primary);
  color: var(--white);
  box-shadow: 0 4px 15px rgba(108, 99, 255, 0.3);
}

.btn-primary:hover {
  transform: translateY(-3px);
  box-shadow: 0 8px 25px rgba(108, 99, 255, 0.5);
  color: var(--white);
}

.btn-secondary {
  background: transparent;
  color: var(--primary);
  border: 2px solid var(--primary);
}

.btn-secondary:hover {
  background: var(--primary);
  color: var(--white);
  transform: translateY(-3px);
  box-shadow: 0 4px 15px rgba(108, 99, 255, 0.3);
}

.btn-accent {
  background: var(--gradient-accent);
  color: var(--white);
  box-shadow: 0 4px 15px rgba(255, 101, 132, 0.3);
}

.btn-accent:hover {
  transform: translateY(-3px);
  box-shadow: 0 8px 25px rgba(255, 101, 132, 0.5);
}

/* ===== GLASS EFFECT ===== */
.glass-card {
  background: var(--glass);
  backdrop-filter: blur(10px);
  border: 1px solid var(--glass-border);
  border-radius: var(--radius);
  transition: var(--transition);
}

.glass-card:hover {
  border-color: var(--primary);
  box-shadow: var(--shadow-glow);
}

/* ===== HEADER ===== */
.header-fixed {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  z-index: 1000;
  background: rgba(15, 23, 42, 0.95);
  backdrop-filter: blur(10px);
  padding: 15px 0;
  border-bottom: 1px solid var(--glass-border);
  box-shadow: 0 4px 30px rgba(0, 0, 0, 0.3);
}

.header-container {
  display: flex;
  justify-content: space-between;
  align-items: center;
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
}

.logo {
  display: flex;
  align-items: center;
}

.logo-text {
  font-size: 1.5rem;
  font-weight: 800;
  background: var(--gradient-primary);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  text-transform: uppercase;
  letter-spacing: 1px;
}

.site-logo {
  max-height: 45px !important;
  width: auto !important;
  display: block !important;
  border-radius: 8px;
}

.nav-menu {
  display: flex;
  list-style: none;
  gap: 30px;
  margin: 0;
  padding: 0;
}

.nav-link {
  text-decoration: none;
  color: var(--text-light);
  font-weight: 500;
  font-size: 0.95rem;
  transition: var(--transition);
  position: relative;
  padding: 5px 0;
}

.nav-link:hover {
  color: var(--primary);
}

.nav-link::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 0;
  height: 2px;
  background: var(--gradient-primary);
  transition: var(--transition);
}

.nav-link:hover::after,
.nav-link.active::after {
  width: 100%;
}

.nav-link.active {
  color: var(--primary);
}

.menu-toggle {
  display: none;
  cursor: pointer;
  font-size: 1.5rem;
  color: var(--text-light);
  z-index: 1001;
  width: 40px;
  height: 40px;
  align-items: center;
  justify-content: center;
  background: var(--glass);
  border-radius: 50%;
  border: 1px solid var(--glass-border);
}

/* ===== HERO SECTION ===== */
.hero-section {
  min-height: 100vh;
  display: flex;
  align-items: center;
  padding-top: 100px;
  position: relative;
  overflow: hidden;
}

.hero-container {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 50px;
  align-items: center;
}

.hero-badge {
  display: inline-block;
  padding: 8px 16px;
  background: rgba(108, 99, 255, 0.15);
  color: var(--secondary);
  border: 1px solid rgba(54, 209, 220, 0.3);
  border-radius: 50px;
  font-size: 0.85rem;
  font-weight: 600;
  margin-bottom: 25px;
  text-transform: uppercase;
  letter-spacing: 2px;
  animation: fadeInUp 0.6s ease;
}

.hero-title {
  font-size: 3.5rem;
  line-height: 1.1;
  margin-bottom: 20px;
  animation: fadeInUp 0.8s ease;
}

.hero-title span {
  background: var(--gradient-secondary);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  display: block;
}

.hero-subtitle {
  font-size: 1.2rem;
  color: var(--text-muted);
  margin-bottom: 30px;
  max-width: 90%;
  animation: fadeInUp 1s ease;
}

.hero-stats {
  display: flex;
  gap: 30px;
  margin-bottom: 35px;
  animation: fadeInUp 1.2s ease;
}

.hero-stat-item {
  text-align: left;
}

.hero-stat-number {
  font-size: 2.2rem;
  font-weight: 800;
  background: var(--gradient-primary);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  line-height: 1;
  display: block;
  margin-bottom: 5px;
}

.hero-stat-label {
  font-size: 0.85rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 1px;
}

.hero-btns {
  display: flex;
  gap: 20px;
  animation: fadeInUp 1.4s ease;
}

.hero-image-wrapper {
  position: relative;
  animation: floatIn 1s ease;
}

.hero-card {
  position: relative;
  width: 100%;
  max-width: 400px;
  height: 500px;
  background: var(--glass);
  border-radius: 30px;
  border: 1px solid var(--glass-border);
  backdrop-filter: blur(20px);
  overflow: hidden;
  margin-left: auto;
  box-shadow: var(--shadow-hover);
}

.hero-card-blob {
  position: absolute;
  width: 300px;
  height: 300px;
  border-radius: 50%;
  filter: blur(60px);
  opacity: 0.5;
  z-index: 1;
}

.blob-1 {
  background: var(--primary);
  top: -50px;
  left: -50px;
  animation: blobMove 10s infinite alternate;
}

.blob-2 {
  background: var(--secondary);
  bottom: -50px;
  right: -50px;
  animation: blobMove 12s infinite alternate-reverse;
}

.hero-img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  border-radius: 30px;
  position: relative;
  z-index: 2;
  opacity: 0.95;
  transition: transform 0.5s ease;
}

.hero-card:hover .hero-img {
  transform: scale(1.05);
}

.hero-float-badge {
  position: absolute;
  z-index: 5;
  background: rgba(15, 23, 42, 0.9);
  border: 1px solid var(--glass-border);
  backdrop-filter: blur(10px);
  padding: 12px 20px;
  border-radius: 50px;
  display: flex;
  align-items: center;
  gap: 10px;
  color: white;
  font-size: 0.9rem;
  font-weight: 600;
  box-shadow: var(--shadow);
}

.hero-fb-1 {
  top: 50px;
  left: -25px;
  animation: badgeFloat 4s ease-in-out infinite;
}

.hero-fb-2 {
  bottom: 50px;
  right: -25px;
  animation: badgeFloat 4.5s ease-in-out infinite 1s;
}

.hero-icon {
  width: 35px;
  height: 35px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1rem;
  background: var(--gradient-accent);
}

@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(30px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes floatIn {
  from {
    opacity: 0;
    transform: scale(0.9);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes blobMove {
  0% {
    transform: translate(0, 0) scale(1);
  }
  100% {
    transform: translate(30px, -30px) scale(1.2);
  }
}

@keyframes badgeFloat {
  0%, 100% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(-15px);
  }
}

/* ===== PROFILES SECTION ===== */
.profiles-section {
  background: var(--dark);
  position: relative;
}

.profile-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 20px;
  margin-top: 30px;
}

.profile-card {
  height: 350px;
  perspective: 1000px;
  cursor: pointer;
}

.profile-card-inner {
  position: relative;
  width: 100%;
  height: 100%;
  text-align: center;
  transition: transform 0.8s;
  transform-style: preserve-3d;
  border-radius: var(--radius);
  box-shadow: var(--shadow);
}

.profile-card:hover .profile-card-inner {
  transform: rotateY(180deg);
}

.profile-card-front,
.profile-card-back {
  position: absolute;
  width: 100%;
  height: 100%;
  -webkit-backface-visibility: hidden;
  backface-visibility: hidden;
  border-radius: var(--radius);
  padding: 25px;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
}

.profile-card-front {
  background: var(--glass);
  border: 1px solid var(--glass-border);
  backdrop-filter: blur(10px);
}

.profile-card-back {
  background: var(--gradient-primary);
  transform: rotateY(180deg);
  color: var(--white);
}

.profile-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  width: 100%;
  margin-bottom: 20px;
}

.profile-logo {
  width: 50px;
  height: 50px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.5rem;
  color: var(--white);
  box-shadow: var(--shadow);
}

.profile-badge {
  background: var(--gradient-accent);
  color: var(--white);
  padding: 5px 12px;
  border-radius: 20px;
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 1px;
}

.profile-name {
  font-size: 1.3rem;
  margin: 10px 0 5px;
  color: var(--text-light);
}

.profile-username {
  color: var(--text-muted);
  font-size: 0.9rem;
  margin-bottom: 20px;
}

.profile-stats {
  display: flex;
  gap: 20px;
  margin: 20px 0;
}

.profile-stat {
  text-align: center;
}

.profile-stat-number {
  font-size: 1.5rem;
  font-weight: 800;
  background: var(--gradient-primary);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  line-height: 1;
}

.profile-stat-label {
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-top: 5px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.profile-cta {
  display: flex;
  align-items: center;
  gap: 5px;
  margin-top: 15px;
  color: var(--primary);
  font-size: 0.85rem;
  font-weight: 600;
}

.profile-card-back h4 {
  color: var(--white);
  margin-bottom: 15px;
  font-size: 1.2rem;
}

.profile-metrics {
  display: flex;
  gap: 20px;
  margin: 15px 0;
}

.metric {
  text-align: center;
}

.metric-value {
  font-size: 1.3rem;
  font-weight: 700;
}

.metric-label {
  font-size: 0.7rem;
  opacity: 0.9;
}

.profile-description {
  margin: 15px 0;
  font-size: 0.9rem;
  line-height: 1.5;
  opacity: 0.9;
}

.profile-card-back .btn {
  background: rgba(255, 255, 255, 0.2);
  color: var(--white);
  border: 1px solid rgba(255, 255, 255, 0.3);
  margin-top: 15px;
  padding: 10px 20px;
  font-size: 0.85rem;
}

.profile-card-back .btn:hover {
  background: var(--white);
  color: var(--primary);
}

/* ===== SEARCH CONTAINER ===== */
.search-container-wrapper-full {
  background: var(--glass);
  border-radius: var(--radius);
  padding: 30px;
  border: 1px solid var(--glass-border);
  width: 100%;
  margin: 30px 0;
  box-shadow: var(--shadow);
}

.search-header {
  text-align: center;
  margin-bottom: 20px;
}

.search-header h3 {
  color: var(--text-light);
  font-size: 1.4rem;
  margin-bottom: 5px;
}

.search-header p {
  color: var(--text-muted);
  font-size: 0.95rem;
}

.search-wrapper {
  display: flex;
  flex-direction: column;
  gap: 20px;
  max-width: 800px;
  margin: 0 auto;
}

.search-box {
  display: flex;
  gap: 15px;
  width: 100%;
}

.search-input-wrapper {
  flex: 1;
  position: relative;
}

.search-input {
  width: 100%;
  padding: 15px 15px 15px 45px;
  background: rgba(15, 23, 42, 0.8);
  border: 2px solid var(--glass-border);
  border-radius: var(--radius);
  color: var(--text-light);
  font-size: 1rem;
  transition: var(--transition);
}

.search-input:focus {
  outline: none;
  border-color: var(--primary);
  background: rgba(15, 23, 42, 0.95);
  box-shadow: 0 0 0 3px rgba(108, 99, 255, 0.2);
}

.search-input::placeholder {
  color: var(--text-muted);
}

.search-icon {
  position: absolute;
  left: 15px;
  top: 50%;
  transform: translateY(-50%);
  color: var(--primary);
  font-size: 1.1rem;
}

.search-btn {
  padding: 15px 30px;
  font-size: 1rem;
}

.search-filters {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
  justify-content: center;
}

.filter-btn {
  padding: 8px 16px;
  background: rgba(15, 23, 42, 0.5);
  border: 1px solid var(--glass-border);
  border-radius: 30px;
  color: var(--text-light);
  font-size: 0.85rem;
  cursor: pointer;
  transition: var(--transition);
}

.filter-btn:hover {
  background: rgba(108, 99, 255, 0.2);
  border-color: var(--primary);
}

.filter-btn.active {
  background: var(--gradient-primary);
  border-color: transparent;
  color: var(--white);
}

.search-stats {
  color: var(--text-muted);
  font-size: 0.9rem;
  text-align: center;
  margin-top: 10px;
}

.search-stats .highlight {
  color: var(--primary);
  font-weight: 600;
  font-size: 1.1rem;
}

.profile-card.hidden {
  display: none !important;
}

.no-results {
  text-align: center;
  padding: 50px;
  color: var(--text-muted);
  font-size: 1rem;
  display: none;
  grid-column: 1 / -1;
}

.no-results.show {
  display: block;
}

.no-results i {
  font-size: 3rem;
  margin-bottom: 20px;
  color: var(--primary);
  opacity: 0.5;
}

/* ===== SKILLS SECTION ===== */
.skills-section {
  background: var(--darker);
}

.skills-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 25px;
  margin-top: 30px;
}

.skill-category {
  background: var(--glass);
  border-radius: var(--radius);
  padding: 25px;
  border: 1px solid var(--glass-border);
  transition: var(--transition);
}

.skill-category:hover {
  transform: translateY(-5px);
  border-color: var(--primary);
  box-shadow: var(--shadow-hover);
}

.skill-header {
  display: flex;
  align-items: center;
  gap: 15px;
  margin-bottom: 25px;
}

.skill-icon {
  width: 60px;
  height: 60px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.5rem;
  color: var(--white);
  background: var(--gradient-primary);
  box-shadow: var(--shadow);
}

.skill-header h3 {
  margin: 0;
  font-size: 1.3rem;
  color: var(--text-light);
}

.skill-list {
  display: flex;
  flex-direction: column;
  gap: 15px;
}

.skill-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.skill-name {
  font-weight: 500;
  color: var(--text-light);
}

.skill-level {
  display: flex;
  align-items: center;
  gap: 10px;
}

.skill-level-bar {
  width: 120px;
  height: 6px;
  background: rgba(255, 255, 255, 0.1);
  border-radius: 3px;
  overflow: hidden;
}

.skill-level-fill {
  height: 100%;
  background: var(--gradient-primary);
  border-radius: 3px;
  transition: width 1s ease;
}

/* ===== TIMELINE SECTION ===== */
.timeline-section {
  background: var(--dark);
}

.timeline {
  position: relative;
  max-width: 900px;
  margin: 40px auto 0;
}

.timeline::before {
  content: '';
  position: absolute;
  left: 50%;
  transform: translateX(-50%);
  width: 4px;
  height: 100%;
  background: var(--gradient-primary);
  border-radius: 2px;
}

.timeline-item {
  position: relative;
  margin-bottom: 40px;
  width: calc(50% - 30px);
}

.timeline-item:nth-child(odd) {
  left: 0;
}

.timeline-item:nth-child(even) {
  left: calc(50% + 30px);
}

.timeline-content {
  background: var(--glass);
  border-radius: var(--radius);
  padding: 25px;
  border: 1px solid var(--glass-border);
  position: relative;
  transition: var(--transition);
}

.timeline-content:hover {
  transform: translateY(-5px);
  border-color: var(--primary);
  box-shadow: var(--shadow);
}

.timeline-date {
  background: var(--gradient-primary);
  color: var(--white);
  padding: 5px 15px;
  border-radius: 25px;
  font-size: 0.85rem;
  font-weight: 600;
  display: inline-block;
  margin-bottom: 15px;
}

.timeline-content h3 {
  margin: 0 0 8px;
  font-size: 1.3rem;
  color: var(--text-light);
}

.timeline-content .company {
  color: var(--secondary);
  font-weight: 600;
  margin-bottom: 15px;
  display: block;
}

.timeline-content p {
  color: var(--text-muted);
  line-height: 1.6;
}

/* ===== PROJECTS SECTION ===== */
.projects-section {
  background: var(--darker);
}

.project-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
  gap: 25px;
  margin-top: 30px;
}

.project-card {
  background: var(--gradient-glass);
  border-radius: var(--radius);
  padding: 25px;
  border: 1px solid var(--glass-border);
  transition: var(--transition);
  cursor: pointer;
  position: relative;
  overflow: hidden;
  display: flex;
  flex-direction: column;
  height: 100%;
  backdrop-filter: blur(10px);
  box-shadow: var(--shadow);
}

.project-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: -100%;
  width: 100%;
  height: 100%;
  background: linear-gradient(90deg, transparent, rgba(108, 99, 255, 0.1), transparent);
  transition: left 0.7s ease;
  z-index: 1;
}

.project-card:hover::before {
  left: 100%;
}

.project-card:hover {
  transform: translateY(-8px);
  border-color: var(--primary);
  box-shadow: var(--shadow-hover), var(--shadow-glow);
}

.project-image-container {
  position: relative;
  width: 100%;
  height: 200px;
  border-radius: var(--radius);
  overflow: hidden;
  margin-bottom: 20px;
  background: var(--gradient-dark);
}

.project-image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.7s ease;
}

.project-card:hover .project-image {
  transform: scale(1.1);
}

.project-image-overlay {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: linear-gradient(to bottom, transparent 60%, rgba(15, 23, 42, 0.9));
  display: flex;
  align-items: flex-end;
  padding: 15px;
  opacity: 0;
  transition: opacity 0.3s ease;
}

.project-card:hover .project-image-overlay {
  opacity: 1;
}

.project-category {
  background: var(--gradient-primary);
  color: var(--white);
  padding: 5px 12px;
  border-radius: 20px;
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
}

.project-title {
  font-size: 1.4rem;
  margin-bottom: 10px;
  color: var(--text-light);
  line-height: 1.3;
}

.project-description {
  color: var(--text-muted);
  margin-bottom: 20px;
  line-height: 1.6;
  font-size: 0.95rem;
  flex-grow: 1;
}

.project-tags {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
  margin-top: 15px;
}

.project-tag {
  background: rgba(108, 99, 255, 0.1);
  color: var(--primary);
  padding: 5px 12px;
  border-radius: 20px;
  font-size: 0.75rem;
  font-weight: 500;
  border: 1px solid rgba(108, 99, 255, 0.2);
}

.project-meta {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-top: 20px;
  padding-top: 15px;
  border-top: 1px solid var(--glass-border);
  font-size: 0.85rem;
}

.project-date {
  display: flex;
  align-items: center;
  gap: 5px;
  color: var(--text-muted);
}

.project-read-more {
  color: var(--primary);
  font-weight: 600;
  transition: var(--transition);
  display: flex;
  align-items: center;
  gap: 5px;
}

.project-card:hover .project-read-more {
  color: var(--secondary);
  transform: translateX(5px);
}

/* ===== CONTACT SECTION ===== */
.contact-section {
  background: var(--dark);
}

.contact-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 40px;
  margin-top: 40px;
}

.contact-info {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 20px;
  margin-bottom: 30px;
}

.contact-item {
  background: var(--glass);
  border-radius: var(--radius);
  padding: 25px;
  text-align: center;
  border: 1px solid var(--glass-border);
  transition: var(--transition);
}

.contact-item:hover {
  transform: translateY(-5px);
  border-color: var(--primary);
  box-shadow: var(--shadow);
}

.contact-icon {
  font-size: 2rem;
  color: var(--primary);
  margin-bottom: 15px;
}

.contact-item h3 {
  margin-bottom: 10px;
  font-size: 1.1rem;
  color: var(--text-light);
}

.contact-item p {
  color: var(--text-muted);
  font-size: 0.9rem;
  margin: 0;
}

.social-links-large {
  display: flex;
  justify-content: center;
  gap: 15px;
  margin-top: 20px;
}

.social-link-large {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 50px;
  height: 50px;
  background: var(--glass);
  border-radius: 50%;
  color: var(--text-light);
  font-size: 1.2rem;
  transition: var(--transition);
  border: 1px solid var(--glass-border);
}

.social-link-large:hover {
  background: var(--gradient-primary);
  color: var(--white);
  transform: translateY(-5px);
  border-color: transparent;
  box-shadow: var(--shadow);
}

.contact-form-wrapper {
  background: var(--glass);
  border-radius: var(--radius);
  padding: 30px;
  border: 1px solid var(--glass-border);
}

.contact-form-wrapper h3 {
  text-align: center;
  margin-bottom: 25px;
  color: var(--text-light);
  font-size: 1.3rem;
}

.contact-form {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.form-group label {
  color: var(--text-light);
  font-weight: 500;
  font-size: 0.9rem;
}

.form-control {
  padding: 12px 15px;
  border: 2px solid var(--glass-border);
  border-radius: var(--radius);
  background: rgba(15, 23, 42, 0.6);
  color: var(--text-light);
  font-size: 0.95rem;
  transition: var(--transition);
}

.form-control:focus {
  outline: none;
  border-color: var(--primary);
  background: rgba(15, 23, 42, 0.8);
  box-shadow: 0 0 0 3px rgba(108, 99, 255, 0.2);
}

.form-control::placeholder {
  color: rgba(255, 255, 255, 0.3);
}

textarea.form-control {
  min-height: 120px;
  resize: vertical;
}

.submit-btn {
  margin-top: 10px;
  padding: 14px 30px;
}

/* ===== NEWSLETTER SECTION ===== */
.newsletter-section {
  background: var(--gradient-dark);
  padding: 60px 0;
  text-align: center;
}

.newsletter-section .section-header h2,
.newsletter-section .section-subtitle {
  color: var(--white);
}

.newsletter-section .section-header h2::after {
  background: var(--white);
}

.newsletter-form {
  max-width: 500px;
  margin: 30px auto 0;
  display: flex;
  gap: 15px;
}

.newsletter-input {
  flex: 1;
  padding: 15px 20px;
  border: 2px solid rgba(255, 255, 255, 0.2);
  border-radius: var(--radius);
  background: rgba(255, 255, 255, 0.1);
  color: var(--white);
  font-size: 1rem;
  transition: var(--transition);
}

.newsletter-input:focus {
  outline: none;
  border-color: var(--white);
  background: rgba(255, 255, 255, 0.15);
}

.newsletter-input::placeholder {
  color: rgba(255, 255, 255, 0.6);
}

.newsletter-form .btn-accent {
  background: var(--white);
  color: var(--primary);
  border: none;
}

.newsletter-form .btn-accent:hover {
  background: var(--primary);
  color: var(--white);
  transform: translateY(-3px);
  box-shadow: 0 8px 25px rgba(255, 255, 255, 0.2);
}

/* ===== FOOTER ===== */
.footer {
  background: var(--darker);
  color: var(--white);
  padding: 60px 0 30px;
  text-align: center;
  border-top: 1px solid var(--glass-border);
}

.footer-content {
  max-width: 700px;
  margin: 0 auto;
}

.footer-logo {
  font-size: 2rem;
  font-weight: 800;
  margin-bottom: 20px;
  background: var(--gradient-primary);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.footer-about {
  color: var(--text-muted);
  margin-bottom: 30px;
  line-height: 1.8;
  font-size: 1rem;
}

.footer .social-links-large {
  margin-bottom: 30px;
}

.footer-bottom {
  padding-top: 30px;
  border-top: 1px solid var(--glass-border);
  color: var(--text-muted);
  font-size: 0.9rem;
}

/* ===== MODAL ===== */
.view-modal {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0, 0, 0, 0.95);
  display: none;
  justify-content: center;
  align-items: center;
  z-index: 9999;
  padding: 20px;
}

.view-modal.active {
  display: flex;
  animation: modalFadeIn 0.3s ease;
}

@keyframes modalFadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

.modal-content {
  background: var(--dark);
  border-radius: var(--radius);
  width: 100%;
  max-width: 700px;
  max-height: 85vh;
  overflow-y: auto;
  position: relative;
  border: 1px solid var(--glass-border);
  animation: modalSlideIn 0.3s ease;
}

@keyframes modalSlideIn {
  from {
    opacity: 0;
    transform: translateY(-30px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.modal-header {
  padding: 20px 25px;
  background: var(--gradient-dark);
  color: var(--white);
  display: flex;
  justify-content: space-between;
  align-items: center;
  position: sticky;
  top: 0;
  z-index: 1;
  border-bottom: 1px solid var(--glass-border);
}

.modal-header h2 {
  color: var(--white);
  margin: 0;
  font-size: 1.5rem;
}

.close-modal {
  background: none;
  border: none;
  color: var(--white);
  font-size: 2rem;
  cursor: pointer;
  line-height: 1;
  transition: var(--transition);
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
}

.close-modal:hover {
  transform: rotate(90deg);
  background: rgba(255, 255, 255, 0.1);
}

.modal-body {
  padding: 25px;
}

.modal-image {
  width: 100%;
  height: 300px;
  object-fit: cover;
  border-radius: var(--radius);
  margin-bottom: 20px;
  box-shadow: var(--shadow);
}

.modal-description {
  font-size: 1rem;
  line-height: 1.6;
  color: var(--text-light);
  margin-bottom: 20px;
}

.modal-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.modal-tag {
  background: rgba(108, 99, 255, 0.2);
  color: var(--primary);
  padding: 6px 14px;
  border-radius: 20px;
  font-size: 0.85rem;
  font-weight: 500;
  border: 1px solid rgba(108, 99, 255, 0.3);
}

/* ===== LOADING SPINNER ===== */
.loading-spinner {
  display: none;
  text-align: center;
  padding: 50px;
}

.loading-spinner.active {
  display: block;
}

.spinner {
  width: 40px;
  height: 40px;
  border: 4px solid rgba(255, 255, 255, 0.1);
  border-top-color: var(--primary);
  border-radius: 50%;
  animation: spin 1s linear infinite;
  margin: 0 auto 15px;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

/* ===== BLOG POST PAGE ===== */
.blog-post-page {
  background: var(--darker);
  min-height: 100vh;
  padding-top: 80px;
}

.post-wrapper {
  max-width: 800px;
  margin: 0 auto;
  padding: 30px 0;
}

.post-container {
  background: var(--glass);
  border-radius: var(--radius);
  padding: 40px;
  border: 1px solid var(--glass-border);
  margin-bottom: 30px;
  backdrop-filter: blur(10px);
}

.post-header {
  margin-bottom: 30px;
  padding-bottom: 20px;
  border-bottom: 1px solid var(--glass-border);
}

.post-title {
  font-size: 2.5rem;
  color: var(--text-light);
  margin-bottom: 20px;
  line-height: 1.2;
}

.post-meta {
  display: flex;
  gap: 20px;
  flex-wrap: wrap;
  color: var(--text-muted);
  font-size: 0.9rem;
}

.post-meta-item {
  display: flex;
  align-items: center;
  gap: 6px;
}

.post-meta-item i {
  color: var(--primary);
}

.post-content {
  font-size: 1.1rem;
  line-height: 1.8;
  color: var(--text-light);
  margin-bottom: 30px;
}

.post-content p {
  color: var(--text-muted);
  margin-bottom: 1.5rem;
}

.post-content h1,
.post-content h2,
.post-content h3,
.post-content h4,
.post-content h5,
.post-content h6 {
  color: var(--text-light);
  margin: 2rem 0 1rem;
}

.post-content a {
  color: var(--secondary);
  text-decoration: none;
}

.post-content a:hover {
  color: var(--primary);
  text-decoration: underline;
}

.post-content blockquote {
  border-left: 4px solid var(--primary);
  padding-left: 1.5rem;
  margin: 2rem 0;
  font-style: italic;
  color: var(--text-muted);
  background: rgba(108, 99, 255, 0.05);
  border-radius: 0 var(--radius) var(--radius) 0;
}

.post-content code {
  background: rgba(108, 99, 255, 0.1);
  padding: 3px 8px;
  border-radius: 4px;
  font-family: 'Courier New', monospace;
  font-size: 0.9em;
  color: var(--secondary);
}

.post-author {
  display: flex;
  align-items: center;
  gap: 20px;
  padding: 25px;
  background: rgba(15, 23, 42, 0.5);
  border-radius: var(--radius);
  margin: 30px 0;
  border: 1px solid var(--glass-border);
}

.author-avatar {
  width: 80px;
  height: 80px;
  border-radius: 50%;
  object-fit: cover;
  border: 3px solid var(--primary);
}

.author-info h4 {
  color: var(--text-light);
  margin-bottom: 8px;
  font-size: 1.2rem;
}

.author-bio {
  color: var(--text-muted);
  font-size: 0.95rem;
  line-height: 1.5;
}

.post-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  margin: 20px 0;
}

.post-tag {
  background: rgba(108, 99, 255, 0.2);
  color: var(--primary);
  padding: 8px 18px;
  border-radius: 25px;
  font-size: 0.85rem;
  font-weight: 500;
  text-decoration: none;
  border: 1px solid rgba(108, 99, 255, 0.3);
  transition: var(--transition);
}

.post-tag:hover {
  background: var(--gradient-primary);
  color: var(--white);
  transform: translateY(-2px);
}

.comments-section {
  background: var(--glass);
  border-radius: var(--radius);
  padding: 40px;
  border: 1px solid var(--glass-border);
  margin-top: 30px;
}

.comments-title {
  color: var(--text-light);
  margin-bottom: 25px;
  font-size: 1.4rem;
  padding-bottom: 15px;
  border-bottom: 1px solid var(--glass-border);
}

.back-to-home {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  color: var(--primary);
  text-decoration: none;
  font-weight: 600;
  padding: 12px 25px;
  border: 2px solid var(--primary);
  border-radius: var(--radius);
  transition: var(--transition);
  margin-top: 30px;
}

.back-to-home:hover {
  background: var(--primary);
  color: var(--white);
  transform: translateX(-5px);
}

/* ===== RESPONSIVE DESIGN ===== */
@media (max-width: 1200px) {
  .container {
    max-width: 960px;
  }

  .profile-grid {
    grid-template-columns: repeat(3, 1fr);
  }

  .hero-title {
    font-size: 3rem;
  }

  .hero-card {
    height: 450px;
  }
}

@media (max-width: 992px) {
  .container {
    max-width: 720px;
  }

  .hero-container {
    grid-template-columns: 1fr;
    text-align: center;
    gap: 40px;
  }

  .hero-text-content {
    order: 2;
  }

  .hero-btns,
  .hero-stats {
    justify-content: center;
  }

  .hero-subtitle {
    max-width: 100%;
  }

  .hero-image-wrapper {
    order: 1;
    display: flex;
    justify-content: center;
  }

  .hero-card {
    margin: 0 auto;
  }

  .profile-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .contact-grid {
    grid-template-columns: 1fr;
    gap: 30px;
  }

  .timeline::before {
    left: 20px;
  }

  .timeline-item {
    width: calc(100% - 50px);
    left: 50px !important;
  }

  .menu-toggle {
    display: flex;
  }

  .nav-menu {
    position: fixed;
    top: 0;
    left: -100%;
    width: 280px;
    height: 100vh;
    background: var(--dark);
    flex-direction: column;
    align-items: flex-start;
    justify-content: flex-start;
    padding: 100px 30px 30px;
    transition: var(--transition);
    box-shadow: var(--shadow-hover);
    z-index: 1000;
    border-right: 1px solid var(--glass-border);
  }

  .nav-menu.active {
    left: 0;
  }

  .nav-link {
    font-size: 1rem;
    padding: 12px 0;
    width: 100%;
  }
}

@media (max-width: 768px) {
  .container {
    max-width: 540px;
  }

  h1 {
    font-size: 2.5rem;
  }

  h2 {
    font-size: 2rem;
  }

  .section-header h2 {
    font-size: 2rem;
  }

  .hero-title {
    font-size: 2.5rem;
  }

  .hero-stats {
    flex-wrap: wrap;
    gap: 20px;
  }

  .profile-grid {
    grid-template-columns: 1fr;
    gap: 15px;
  }

  .profile-card {
    height: 320px;
  }

  .skills-grid {
    grid-template-columns: 1fr;
  }

  .project-grid {
    grid-template-columns: 1fr;
  }

  .newsletter-form {
    flex-direction: column;
  }

  .contact-info {
    grid-template-columns: 1fr;
  }

  .search-box {
    flex-direction: column;
  }

  .search-btn {
    width: 100%;
  }

  .post-container {
    padding: 25px;
  }

  .post-title {
    font-size: 2rem;
  }

  .post-author {
    flex-direction: column;
    text-align: center;
  }

  .author-avatar {
    width: 100px;
    height: 100px;
  }
}

@media (max-width: 576px) {
  .hero-card {
    height: 400px;
    max-width: 320px;
  }

  .hero-float-badge {
    padding: 8px 15px;
    font-size: 0.8rem;
  }

  .hero-fb-1 {
    top: 20px;
    left: -10px;
  }

  .hero-fb-2 {
    bottom: 20px;
    right: -10px;
  }

  .profile-card {
    height: 300px;
  }

  .post-container {
    padding: 20px;
  }

  .post-title {
    font-size: 1.8rem;
  }

  .post-meta {
    flex-direction: column;
    gap: 8px;
  }

  .comments-section {
    padding: 25px;
  }
}

body.script:
//
(function() {
  'use strict';

  // Mobile Menu Toggle
  function initMobileMenu() {
    const menuToggle = document.querySelector('.menu-toggle');
    const navMenu = document.querySelector('.nav-menu');

    if (menuToggle && navMenu) {
      menuToggle.addEventListener('click', function(e) {
        e.stopPropagation();
        navMenu.classList.toggle('active');
        menuToggle.innerHTML = navMenu.classList.contains('active') ? 
          '<i class="fas fa-times"></i>' : '<i class="fas fa-bars"></i>';
      });

      document.addEventListener('click', function(e) {
        if (!navMenu.contains(e.target) && !menuToggle.contains(e.target)) {
          navMenu.classList.remove('active');
          menuToggle.innerHTML = '<i class="fas fa-bars"></i>';
        }
      });

      navMenu.querySelectorAll('a').forEach(link => {
        link.addEventListener('click', function() {
          navMenu.classList.remove('active');
          menuToggle.innerHTML = '<i class="fas fa-bars"></i>';
        });
      });
    }
  }

  // Smooth Scrolling
  function initSmoothScroll() {
    if (document.querySelector('.blog-post-page')) return;

    document.addEventListener('click', function(e) {
      const link = e.target.closest('a[href^="#"]');
      if (!link) return;

      const targetId = link.getAttribute('href');
      if (targetId === '#') return;

      const target = document.querySelector(targetId);
      if (target) {
        e.preventDefault();
        window.scrollTo({
          top: target.offsetTop - 80,
          behavior: 'smooth'
        });
      }
    });
  }

  // Modal Functions
  function initModal() {
    const modal = document.getElementById('viewModal');
    const closeBtn = document.getElementById('closeModal');

    if (closeBtn && modal) {
      closeBtn.addEventListener('click', function() {
        modal.classList.remove('active');
        document.body.classList.remove('modal-open');
      });

      modal.addEventListener('click', function(e) {
        if (e.target === modal) {
          modal.classList.remove('active');
          document.body.classList.remove('modal-open');
        }
      });

      document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape' && modal.classList.contains('active')) {
          modal.classList.remove('active');
          document.body.classList.remove('modal-open');
        }
      });
    }
  }

  window.openViewModal = function(projectId) {
    const modal = document.getElementById('viewModal');
    if (modal) {
      modal.classList.add('active');
      document.body.classList.add('modal-open');
    }
  };

  // Profile Search
  function initProfileSearch() {
    const searchInput = document.getElementById('profileSearch');
    const searchButton = document.getElementById('searchButton');
    const filterButtons = document.querySelectorAll('.filter-btn');
    const profileCards = document.querySelectorAll('.profile-card');
    const noResults = document.getElementById('noResults');
    const visibleCount = document.getElementById('visibleCount');
    const totalCount = document.getElementById('totalCount');

    if (totalCount) {
      totalCount.textContent = profileCards.length;
    }

    function updateVisibleCount() {
      const visible = document.querySelectorAll('.profile-card:not(.hidden)').length;
      if (visibleCount) {
        visibleCount.textContent = visible;
      }
      if (noResults) {
        if (visible === 0) {
          noResults.classList.add('show');
        } else {
          noResults.classList.remove('show');
        }
      }
    }

    function performSearch() {
      const searchTerm = searchInput ? searchInput.value.toLowerCase().trim() : '';
      const activeFilter = document.querySelector('.filter-btn.active');
      const filter = activeFilter ? activeFilter.dataset.filter : 'all';

      profileCards.forEach(card => {
        const platform = card.dataset.platform || '';
        const type = card.dataset.type || '';
        const name = card.dataset.name || '';
        const profileName = card.querySelector('.profile-name')?.textContent.toLowerCase() || '';
        const username = card.querySelector('.profile-username')?.textContent.toLowerCase() || '';

        const matchesSearch = !searchTerm || 
          platform.includes(searchTerm) ||
          name.includes(searchTerm) ||
          profileName.includes(searchTerm) ||
          username.includes(searchTerm);

        const matchesFilter = filter === 'all' || type === filter;

        if (matchesSearch && matchesFilter) {
          card.classList.remove('hidden');
        } else {
          card.classList.add('hidden');
        }
      });

      updateVisibleCount();
    }

    if (searchInput) {
      searchInput.addEventListener('input', performSearch);
    }

    if (searchButton) {
      searchButton.addEventListener('click', performSearch);
    }

    filterButtons.forEach(btn => {
      btn.addEventListener('click', function() {
        filterButtons.forEach(b => b.classList.remove('active'));
        this.classList.add('active');
        performSearch();
      });
    });

    updateVisibleCount();
  }

  // Contact Form Submission
  function initContactForm() {
    const contactForm = document.getElementById('contactForm');
    if (!contactForm) return;

    contactForm.addEventListener('submit', function(e) {
      e.preventDefault();

      const submitBtn = this.querySelector('.submit-btn');
      const originalText = submitBtn.innerHTML;

      submitBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Sending...';
      submitBtn.disabled = true;

      setTimeout(() => {
        alert('Thank you for your message! I will get back to you soon.');
        contactForm.reset();
        submitBtn.innerHTML = originalText;
        submitBtn.disabled = false;
      }, 1500);
    });
  }

  // Newsletter Form Submission
  function initNewsletterForm() {
    const newsletterForm = document.getElementById('newsletterForm');
    if (!newsletterForm) return;

    newsletterForm.addEventListener('submit', function(e) {
      e.preventDefault();

      const submitBtn = this.querySelector('.btn-accent');
      const originalText = submitBtn.innerHTML;

      submitBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Subscribing...';
      submitBtn.disabled = true;

      setTimeout(() => {
        alert('Thank you for subscribing to my newsletter!');
        newsletterForm.reset();
        submitBtn.innerHTML = originalText;
        submitBtn.disabled = false;
      }, 1500);
    });
  }

  // Active Navigation Link
  function setActiveNavLink() {
    const sections = document.querySelectorAll('section[id]');
    const navLinks = document.querySelectorAll('.nav-link');

    window.addEventListener('scroll', () => {
      let current = '';
      const scrollPosition = window.scrollY + 100;

      sections.forEach(section => {
        const sectionTop = section.offsetTop;
        const sectionHeight = section.clientHeight;

        if (scrollPosition >= sectionTop && scrollPosition < sectionTop + sectionHeight) {
          current = section.getAttribute('id');
        }
      });

      navLinks.forEach(link => {
        link.classList.remove('active');
        const href = link.getAttribute('href').substring(1);
        if (href === current) {
          link.classList.add('active');
        }
      });
    });
  }

  // Initialize Everything
  function init() {
    initMobileMenu();
    initSmoothScroll();
    initModal();
    initProfileSearch();
    initContactForm();
    initNewsletterForm();
    setActiveNavLink();
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
